# Category: information_disclosure

import Foundation
import UIKit

class AnalyticsModule {
    static let shared = AnalyticsModule()
    
    func logUserInteraction(event: String, userId: String, email: String) {
        let logMessage = "User Interaction: \(event), UserID: \(userId), Email: \(email)"
        NSLog(logMessage)
        print(logMessage)
    }
    
    func logAPIRequest(endpoint: String, method: String, payload: [String: Any]?, token: String?) {
        let payloadDescription = payload == nil ? "No Payload" : payload!.description
        let logMessage = "API Request: Endpoint: \(endpoint), Method: \(method), Token: \(token ?? "No Token"), Payload: \(payloadDescription)"
        NSLog(logMessage)
        print(logMessage)
    }
    
    func logAPIResponse(endpoint: String, statusCode: Int, responsePayload: Data?) {
        let responseString = responsePayload == nil ? "No Response Payload" : String(data: responsePayload!, encoding: .utf8) ?? "Invalid Payload"
        let logMessage = "API Response: Endpoint: \(endpoint), Status: \(statusCode), Response: \(responseString)"
        NSLog(logMessage)
        print(logMessage)
    }
    
    func logUserDataChange(userId: String, changes: [String: Any]) {
        let changeLog = changes.description
        let logMessage = "User Data Change: UserID: \(userId), Changes: \(changeLog)"
        NSLog(logMessage)
        print(logMessage)
    }
    
    func logErrorCondition(error: Error, description: String) {
        let errorMessage = "Error: \(error.localizedDescription), Description: \(description)"
        NSLog(errorMessage)
        print(errorMessage)
    }
}

